// QTP Alpaca Paper Broker Proxy v1.1 (2026-07-10) — token moved to n8n Variable
// QTP_PROXY_TOKEN after secret-scanner alert. FAIL-CLOSED: unset variable rejects everything.
const b = ($input.first().json.body) || {};
const TOKEN = String((typeof $vars !== 'undefined' && $vars.QTP_PROXY_TOKEN) || '');
if (!TOKEN) { throw new Error('QTP_PROXY_TOKEN_NOT_CONFIGURED'); }
if (String(b.token || '') !== TOKEN) { throw new Error('QTP_PROXY_FORBIDDEN'); }
const m = String(b.method || 'GET').toUpperCase();
if (!['GET','POST','DELETE','PATCH'].includes(m)) { throw new Error('QTP_PROXY_METHOD_NOT_ALLOWED: ' + m); }
const isData = b.host === 'data';
if (isData && m !== 'GET') { throw new Error('QTP_PROXY_DATA_HOST_READONLY'); }
const host = isData ? 'https://data.alpaca.markets' : 'https://paper-api.alpaca.markets';
const path = String(b.path || '');
if (!path.startsWith('/v2/')) { throw new Error('QTP_PROXY_PATH_NOT_ALLOWED'); }
return [{ json: { method: m, url: host + path, bodyStr: b.body ? JSON.stringify(b.body) : '' } }];

const r = $input.first().json || {};
if (r.error) {
  return [{ json: { __qtp_proxy_error: { status: r.error.status || null, message: String(r.error.message || r.error).slice(0, 300), body: '' } } }];
}
const sc = Number(r.statusCode || 200);
if (sc >= 400) {
  const bodyTxt = typeof r.body === 'string' ? r.body : JSON.stringify(r.body === undefined ? '' : r.body);
  return [{ json: { __qtp_proxy_error: { status: sc, message: 'HTTP ' + sc, body: String(bodyTxt).slice(0, 500) } } }];
}
return [{ json: { __qtp_proxy_ok: true, status: sc, data: r.body === undefined ? null : r.body } }];
